import React from 'react';
import './ResultCard.css';

export default function ResultCard({ category, impact }) {
  if (!category || !impact) return null;

  return (
    <div className="result-card" style={{ borderColor: impact.color, background: impact.bg }}>
      <div className="result-header">
        <span className="result-icon">{impact.icon}</span>
        <div>
          <p className="result-label">Classified As</p>
          <h2 className="result-category" style={{ color: impact.color }}>{category}</h2>
        </div>
      </div>

      <div className="result-bin" style={{ background: impact.color + '18', borderColor: impact.color + '40' }}>
        <span className="result-bin-label">Disposal Bin</span>
        <span className="result-bin-value" style={{ color: impact.color }}>{impact.bin}</span>
      </div>

      <div className="result-guidance">
        <p className="guidance-title">📋 Disposal Guidance</p>
        <p className="guidance-text">{impact.guidance}</p>
      </div>
    </div>
  );
}
